import { err, resultFromThrowable } from '@agentcash/neverthrow';

import type { BaseJsonError, JsonObject, JsonStringifyValue } from './types';

const type = 'json';

export const jsonErr = (surface: string, error: BaseJsonError) => {
  return err(type, surface, error);
};

export const safeStringifyJson = (
  surface: string,
  value: JsonStringifyValue
) => {
  return resultFromThrowable(
    type,
    surface,
    () => JSON.stringify(value, null, 2),
    () => ({
      cause: 'stringify' as const,
      message: 'Could not stringify JSON',
    })
  );
};

export const safeParseJson = (surface: string, value: string) => {
  return resultFromThrowable(
    type,
    surface,
    () => JSON.parse(value) as JsonObject,
    e => ({
      cause: 'parse' as const,
      message: e instanceof Error ? e.message : 'Could not parse JSON',
    })
  );
};

export const safeToJsonObject = (surface: string, value: unknown) => {
  return safeStringifyJson(surface, value as JsonStringifyValue).andThen(json =>
    safeParseJson(surface, json)
  );
};
